INSERT INTO detections (
  rule_id, name, description, severity, platform,
  mitre_attack_id, mitre_tactic, mitre_technique,
  nist_controls, data_sources, query, query_language, tags,
  expected_alerts_per_day, expected_fp_rate, expected_mttd_hours,
  is_global, tenant_id, log_sources, device_types
) VALUES
('DET-0151', 'Many USB File Copies for User', 'Build a baseline of how many file copies each user does to USB media, and detect when a user copies an uncharacteristically large number of files.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP","Endpoint Detection and Response"}', '{"Data Loss Prevention","EDR","Endpoint"}'),
('DET-0152', 'Basic Malware Outbreak', 'Looks for the same malware occurring on multiple systems in a short period of time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0153', 'Create or delete hidden shares using net.exe', 'This search looks for the creation or deletion of hidden shares using net.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.user) as user values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processs.process_name=net.exe OR Processes.process_name=net1.exe) by Processes.process Processes.process_name Processes.dest | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search (process=*share* OR process=*delete*)| regex process="\S+[$]"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0154', 'Unusually Long VPN Session', 'Detects unusually long VPN sessions, based on a user''s baseline and their peer group.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IP Address Assignment"}', '{}'),
('DET-0155', 'Short Lived Admin Accounts', 'A technique used by attackers is to create an account, take some actions, and then delete it right away. This search will find those accounts on the local system.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Defense Evasion', 'Create Account', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0156', 'Processes with Lookalike (typo) Filenames', 'To evade analysts, attackers will create a service with a name similar to that of a standard Windows service. This search looks for small differences. Idea from David Bianco, formerly of Sqrrl (http://detect-respond.blogspot.com/2016/11/hunting-for-malware-critical-process.html">link).Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0157', 'New User Taking Privileged Actions', 'Record when a user who hasn''t taken privileged actions before suddenly starts.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0158', 'Remote WMI Command Attempt', 'This search looks for wmic.exe being launched with parameters to operate on remote systems.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=wmic.exe  AND Processes.process= */node* by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0159', 'Attempt To Add Certificate To Untrusted Store', 'Attempt to add a certificate to the untrusted certificate store', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '| tstats `summariesonly` count min(_time) values(Processes.process) as process max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=certutil.exe (Processes.process=*-addstore* AND Processes.process=*disallowed* ) by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0160', 'Blacklisted IP Address', 'Generates anomalies for traffic that goes to Blacklisted IPs', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0161', 'New Logon Type for User', 'Windows defines several logon types (Interactive, RemoteInteractive, Network, etc.). Established users rarely generate new logon types. This search will look for that scenario. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0162', 'AWS New API Call Per User', 'Looks for users that are using AWS APIs that they''ve never used before.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1260', 'Execution', 'Determine 3rd party infrastructure services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0163', 'Multiple Outgoing Connections', 'Multiple Outgoing Connections', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0164', 'Geographically Improbable Access Detected against Category', 'To ensure you have a GDPR-mandated audit trail with individual accounts for each person, detect when the same account is logged into twice in a short period of time but from locations very far away, to a GDPR-tagged system.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Audit Trail","Audit Trail","AWS"}', '{"Identity Provider","Active Directory","Audit System","AWS Cloud"}'),
('DET-0165', 'In-Scope System with Windows Update Disabled', 'Any GDPR-tagged systems not receiving updates could jeopardize your GDPR status due to Article 32. Detect systems where the Windows Update service is disabled.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Patch Management"}', '{}'),
('DET-0166', 'Child Processes of Spoolsv.exe', 'This search looks for child processes of spoolsv.exe. This activity is associated with a POC privilege-escalation exploit associated with CVE-2018-8440. Spoolsv.exe is the process associated with the Print Spooler service in Windows and typically runs as SYSTEM.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1068', 'Privilege Escalation', 'Exploitation for Privilege Escalation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process_name) as process_name values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.parent_process_name=spoolsv.exe AND Processes.process_name!=regsvr32.exe by Processes.dest Processes.parent_process Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0167', 'High Or Critical Priority Host With Malware Detected', 'Alerts when an infection is noted on a host with high or critical priority.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0168', 'Registry Keys for Creating SHIM Databases', 'This search looks for registry activity associated with application compatibility shims, which can be leveraged by attackers for various nefarious purposes.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1138', 'Persistence', 'Application Shimming', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Change_Analysis.All_Changes where All_Changes.object_category=registry AND (All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\Custom*" OR All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\InstalledSDB*") by All_Changes.dest, All_Changes.command, All_Changes.user, All_Changes.object, All_Changes.object_path | `drop_dm_object_name("All_Changes")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0169', 'SIEM-E-TA000-XX-File with Samsam Extension', 'The search looks for file writes with extensions consistent with a SamSam ransomware attack.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`| rex field=file_name "(?<file_extension>\.[^\.]+)$" | search file_extension=.stubbin OR file_extension=.berkshire OR file_extension=.satoshi OR file_extension=.sophos OR file_extension=.keyxml', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0170', 'Windows Event Log Clearing Events', 'This use case looks for Windows event codes that indicate the Windows Audit Logs were tampered with.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0171', 'Uncommon Processes On Endpoint', 'This search looks for applications on the endpoint that you have marked as prohibited.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1015', 'Execution', 'Accessibility Features', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest Processes.user Processes.process Processes.process_name | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)` | `uncommon_processes`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0172', 'Spike in Downloaded Documents Per User from Salesforce.com', 'Salesforce.com contains the most critical information for many companies. This example tracks the number of documents downloaded per day per user, to detect exfiltration.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0173', 'Increase in Pages Printed', 'Find users who printed more pages than normal.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0174', 'SIEM-LM-TA000-XX-Significant Increase in Interactive Logons', 'Typically non-admin users will only interactively log into one system per day. A user who starts loggin into many can indicate account compromise and lateral movement. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Lateral Movement', 'Lateral Movement', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0175', 'Abnormally High Number of HTTP Method Events By Src', 'Alerts when a host has an abnormally high number of HTTP requests by http method.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}')
ON CONFLICT (rule_id) DO NOTHING;